import { executeHardAssertions, HardAssertionStageConfig } from '../../src/stages/hard-assertions';
import { EmailMessage } from '../../src/types';
import { ClassificationContext } from '../../src/stages/types';

describe('Hard Assertions Stage', () => {
  const mockConfig: HardAssertionStageConfig = {
    confidenceThresholds: {
      high_confidence: 0.8,
      medium_confidence: 0.5,
      low_confidence: 0.2,
    },
    categorySignals: {
      Financial: {
        hard_assertions: {
          from_domains_ref: {
            source_group: 'banking_domains',
            confidence: 'high',
          },
          subject_prefixes: ['[ALERT]', '[URGENT]'],
          from_addresses: ['noreply@bank.com'],
        },
      },
      Shopping: {
        hard_assertions: {
          subject_prefixes: ['Order Confirmation'],
        },
      },
    },
    domainLookup: {
      banking_domains: {
        high_confidence: [
          { domain: 'chase.com', type: 'bank' },
          { domain: 'bankofamerica.com', type: 'bank' },
        ],
        medium_confidence: [],
        low_confidence: [],
      },
    },
  };

  const createMockEmail = (overrides: Partial<EmailMessage> = {}): EmailMessage => ({
    id: 'test-email-id',
    threadId: 'test-thread-id',
    gmailLabels: [],
    payload: {
      mimeType: 'text/plain',
      headers: [],
    },
    subject: 'Test Subject',
    from: { email: 'test@example.com', raw: 'test@example.com' },
    to: [{ email: 'recipient@example.com', raw: 'recipient@example.com' }],
    date: new Date(),
    isProcessed: false,
    processingPriority: 1,
    ...overrides,
  });

  const createMockContext = (): ClassificationContext => ({
    categoryScores: { Financial: 0.1, Shopping: 0.2 },
    strongIndicatorSeeds: {},
    stageTimings: {},
    configurationRefs: {},
    hardAssertionsApplied: [],
  });

  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe('from_domains_ref assertions', () => {
    it('should trigger hard assertion for matching high-confidence domain', () => {
      const email = createMockEmail({
        from: { email: 'user@chase.com', raw: 'user@chase.com' },
      });
      const context = createMockContext();

      const result = executeHardAssertions(email, context, mockConfig);

      expect(result.categoriesWithHardAssertions).toContain('Financial');
      expect(result.updatedScores.Financial).toBe(0.8); // HIGH_CONFIDENCE_FLOOR
      expect(result.assertionResults).toHaveLength(1);
      expect(result.assertionResults[0]).toMatchObject({
        category: 'Financial',
        triggered: true,
        assertionType: 'from_domain',
        matchedValue: 'chase.com',
        confidence: 'HIGH_CONFIDENCE',
        sourceGroup: 'banking_domains',
      });
      expect(context.hardAssertionsApplied).toContain('Financial');
    });

    it('should not trigger hard assertion for non-matching domain', () => {
      const email = createMockEmail({
        from: { email: 'user@random.com', raw: 'user@random.com' },
      });
      const context = createMockContext();

      const result = executeHardAssertions(email, context, mockConfig);

      expect(result.categoriesWithHardAssertions).not.toContain('Financial');
      expect(result.updatedScores.Financial).toBe(0.1); // Original score unchanged
      expect(result.assertionResults).toHaveLength(0);
    });

    it('should preserve existing higher score when hard assertion floor is lower', () => {
      const email = createMockEmail({
        from: { email: 'user@chase.com', raw: 'user@chase.com' },
      });
      const context = createMockContext();
      context.categoryScores.Financial = 0.9; // Higher than high_confidence threshold

      const result = executeHardAssertions(email, context, mockConfig);

      expect(result.updatedScores.Financial).toBe(0.9); // Should remain at higher score
      expect(result.categoriesWithHardAssertions).toContain('Financial');
    });
  });

  describe('subject_prefixes assertions', () => {
    it('should trigger hard assertion for matching subject prefix', () => {
      const email = createMockEmail({
        subject: '[ALERT] Your account has been compromised',
      });
      const context = createMockContext();

      const result = executeHardAssertions(email, context, mockConfig);

      expect(result.categoriesWithHardAssertions).toContain('Financial');
      expect(result.updatedScores.Financial).toBe(0.8);
      expect(result.assertionResults).toHaveLength(1);
      expect(result.assertionResults[0]).toMatchObject({
        category: 'Financial',
        triggered: true,
        assertionType: 'subject_prefix',
        matchedValue: '[ALERT]',
        confidence: 'HIGH_CONFIDENCE',
      });
    });

    it('should handle case-insensitive subject prefix matching', () => {
      const email = createMockEmail({
        subject: '[alert] Your account needs attention',
      });
      const context = createMockContext();

      const result = executeHardAssertions(email, context, mockConfig);

      expect(result.categoriesWithHardAssertions).toContain('Financial');
      expect(result.assertionResults[0].matchedValue).toBe('[ALERT]');
    });

    it('should stop at first matching prefix', () => {
      const email = createMockEmail({
        subject: '[ALERT] [URGENT] Critical notification',
      });
      const context = createMockContext();

      const result = executeHardAssertions(email, context, mockConfig);

      expect(result.assertionResults).toHaveLength(1);
      expect(result.assertionResults[0].matchedValue).toBe('[ALERT]'); // First match wins
    });
  });

  describe('from_addresses assertions', () => {
    it('should trigger hard assertion for exact email address match', () => {
      const email = createMockEmail({
        from: { email: 'noreply@bank.com', raw: 'noreply@bank.com' },
      });
      const context = createMockContext();

      const result = executeHardAssertions(email, context, mockConfig);

      expect(result.categoriesWithHardAssertions).toContain('Financial');
      expect(result.updatedScores.Financial).toBe(0.8);
      expect(result.assertionResults).toHaveLength(1);
      expect(result.assertionResults[0]).toMatchObject({
        category: 'Financial',
        triggered: true,
        assertionType: 'from_address',
        matchedValue: 'noreply@bank.com',
        confidence: 'HIGH_CONFIDENCE',
      });
    });

    it('should handle normalized email comparison', () => {
      const email = createMockEmail({
        from: { email: 'NoReply@Bank.Com', raw: 'NoReply@Bank.Com' },
      });
      const context = createMockContext();

      const result = executeHardAssertions(email, context, mockConfig);

      expect(result.categoriesWithHardAssertions).toContain('Financial');
      expect(result.assertionResults[0].matchedValue).toBe('noreply@bank.com');
    });
  });

  describe('multiple assertions and categories', () => {
    it('should handle multiple assertion types for same category', () => {
      const email = createMockEmail({
        from: { email: 'user@chase.com', raw: 'user@chase.com' },
        subject: '[ALERT] Account notification',
      });
      const context = createMockContext();

      const result = executeHardAssertions(email, context, mockConfig);

      expect(result.categoriesWithHardAssertions).toContain('Financial');
      expect(result.assertionResults).toHaveLength(2); // Both domain and subject assertions
      expect(result.updatedScores.Financial).toBe(0.8); // Still high confidence floor
    });

    it('should handle assertions across multiple categories', () => {
      const email = createMockEmail({
        subject: 'Order Confirmation #12345',
      });
      const context = createMockContext();

      const result = executeHardAssertions(email, context, mockConfig);

      expect(result.categoriesWithHardAssertions).toContain('Shopping');
      expect(result.updatedScores.Shopping).toBe(0.8);
      expect(result.assertionResults).toHaveLength(1);
      expect(result.assertionResults[0].category).toBe('Shopping');
    });

    it('should not affect categories without matching assertions', () => {
      const email = createMockEmail({
        subject: 'Random newsletter',
        from: { email: 'newsletter@example.com', raw: 'newsletter@example.com' },
      });
      const context = createMockContext();

      const result = executeHardAssertions(email, context, mockConfig);

      expect(result.categoriesWithHardAssertions).toHaveLength(0);
      expect(result.updatedScores.Financial).toBe(0.1); // Original scores preserved
      expect(result.updatedScores.Shopping).toBe(0.2);
      expect(result.assertionResults).toHaveLength(0);
    });
  });

  describe('context tracking and performance', () => {
    it('should track processing duration and update context', () => {
      const email = createMockEmail();
      const context = createMockContext();

      const result = executeHardAssertions(email, context, mockConfig);

      expect(result.processingDurationMs).toBeGreaterThanOrEqual(0);
      expect(context.stageTimings.hard_assertions).toBe(result.processingDurationMs);
      expect(context.configurationRefs.hard_assertions).toBe('category_signals.*.hard_assertions');
    });

    it('should handle empty configuration gracefully', () => {
      const email = createMockEmail();
      const context = createMockContext();
      const emptyConfig: HardAssertionStageConfig = {
        ...mockConfig,
        categorySignals: {},
      };

      const result = executeHardAssertions(email, context, emptyConfig);

      expect(result.categoriesWithHardAssertions).toHaveLength(0);
      expect(result.assertionResults).toHaveLength(0);
      expect(result.updatedScores).toEqual(context.categoryScores);
      expect(result.processingDurationMs).toBeGreaterThanOrEqual(0);
    });
  });

  describe('edge cases', () => {
    it('should handle missing domain lookup gracefully', () => {
      const email = createMockEmail({
        from: { email: 'user@chase.com', raw: 'user@chase.com' },
      });
      const context = createMockContext();
      const configWithMissingDomains: HardAssertionStageConfig = {
        ...mockConfig,
        domainLookup: {}, // Missing banking_domains
      };

      const result = executeHardAssertions(email, context, configWithMissingDomains);

      expect(result.categoriesWithHardAssertions).not.toContain('Financial');
      expect(result.assertionResults).toHaveLength(0);
    });

    it('should handle medium confidence domain references (not hard assertions)', () => {
      const configWithMediumConfidence: HardAssertionStageConfig = {
        ...mockConfig,
        categorySignals: {
          Financial: {
            hard_assertions: {
              from_domains_ref: {
                source_group: 'banking_domains',
                confidence: 'medium', // Not treated as hard assertion
              },
            },
          },
        },
      };

      const email = createMockEmail({
        from: { email: 'user@chase.com', raw: 'user@chase.com' },
      });
      const context = createMockContext();

      const result = executeHardAssertions(email, context, configWithMediumConfidence);

      expect(result.categoriesWithHardAssertions).not.toContain('Financial');
      expect(result.assertionResults).toHaveLength(0);
    });
  });
});

