  };

  const email = createMockEmail({
    from: { email: 'user@paypal.com', raw: 'user@paypal.com' },
  });
  const context = createMockContext();

  const result = executeStrongIndicators(email, context, mediumConfConfig);

  expect(result.categoriesWithStrongIndicators).toContain('Financial');
